import React, { useEffect, useState, useRef } from "react";
import { X, ChevronDown, Search, Filter, CheckCircle, AlertCircle, Plus } from "lucide-react";
import "./Dashboard.css";
import "../../App.css";
import FilterMember from "../../components/common/FilterMember.js";
import { useNavigate } from "react-router-dom";
import api from "../../api";

function CreatePage() {
  const [leaders, setLeaders]           = useState([]);
  const [searchTerm, setSearchTerm]     = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [assignedMembers, setAssignedMembers] = useState([]);
  const [title, setTitle]               = useState("");
  const [crimeDate, setCrimeDate]       = useState("");
  const [description, setDescription]   = useState("");
  const [leader, setLeader]             = useState("");
  const [priority, setPriority]         = useState("High");
  const [status, setStatus]             = useState("Open");
  const [submitting, setSubmitting]     = useState(false);
  const [flashMsg, setFlashMsg]         = useState({ type: "", text: "" });
  const searchDropRef                   = useRef(null);

  const priorities = ["High", "Medium", "Low"];
  const statuses   = ["Open", "Closed", "Archived"];
  const navigate   = useNavigate();

  const flash = (type, text) => {
    setFlashMsg({ type, text });
    setTimeout(() => setFlashMsg({ type: "", text: "" }), 4500);
  };

  // Close search dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (searchDropRef.current && !searchDropRef.current.contains(e.target))
        setSearchResults([]);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleSearch = async (e) => {
    const value = e.target.value;
    setSearchTerm(value);
    if (value.length >= 1) {
      try {
        const res = await api.get(`/users/search?q=${encodeURIComponent(value)}`);
        // Exclude already-assigned members
        const existing = new Set(assignedMembers.map((m) => m._id));
        setSearchResults((Array.isArray(res.data) ? res.data : []).filter((u) => !existing.has(u._id)));
      } catch {
        setSearchResults([]);
      }
    } else {
      setSearchResults([]);
    }
  };

  const addMember = (member) => {
    if (!assignedMembers.find((m) => m._id === member._id)) {
      setAssignedMembers([...assignedMembers, member]);
    }
    setSearchTerm("");
    setSearchResults([]);
  };

  const removeMember = (id) => {
    setAssignedMembers(assignedMembers.filter((m) => m._id !== id));
  };

  const handleCreateCase = async () => {
    if (!title.trim())       return flash("error", "Case title is required.");
    if (!description.trim()) return flash("error", "Please provide a case description.");
    if (!crimeDate)          return flash("error", "Please select a date of crime.");
    if (!leader)             return flash("error", "Please assign a lead investigator.");

    const caseDetails = {
      title: title.trim(),
      description: description.trim(),
      status,
      priority,
      start_date: new Date(crimeDate).toISOString(),
      leader_id: leader,
      member_ids: assignedMembers.map((m) => m._id),
    };

    setSubmitting(true);
    try {
      await api.post("/create-case", caseDetails);
      flash("success", "Case created successfully! Redirecting…");
      setTimeout(() => navigate("/cases"), 1800);
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to create case. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  useEffect(() => {
    api.get("/users/leads")
      .then((res) => setLeaders(Array.isArray(res.data) ? res.data : []))
      .catch(() => {});
  }, []);

  const handleFilterSelection = async (selected) => {
    if (!selected) { setSearchResults([]); return; }
    try {
      const res = await api.get(`/users/filter?q=${encodeURIComponent(selected)}`);
      const existing = new Set(assignedMembers.map((m) => m._id));
      setSearchResults((Array.isArray(res.data) ? res.data : []).filter((u) => !existing.has(u._id)));
      setSearchTerm("");
    } catch {
      setSearchResults([]);
    }
  };

  return (
    <div className="mainContentArea dashboard-bg">
      <div className="createPageWrapper">
        <header className="pageHeader">
          <h1>Create New Case</h1>
          <p>Enter case details and assign the investigating team.</p>
        </header>

        {/* Flash banner */}
        {flashMsg.text && (
          <div
            className={`alertBanner ${flashMsg.type === "success" ? "alertSuccess" : "alertError"}`}
            style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "1.5rem" }}
          >
            {flashMsg.type === "success"
              ? <CheckCircle size={16} />
              : <AlertCircle size={16} />}
            {flashMsg.text}
          </div>
        )}

        <div className="formStack">
          {/* ── Section 1: Case Details ─────────────────────────── */}
          <section className="formSectionCard">
            <div className="sectionHeader" style={{ padding: "1.25rem 1.5rem", borderBottom: "1px solid rgba(255,255,255,0.05)", marginBottom: 0 }}>
              <div className="indicatorDot" />
              <h2 style={{ margin: 0, fontSize: "0.75rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#94a3b8", fontWeight: 800 }}>
                Case Details
              </h2>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Case Title *</label>
                <input
                  type="text"
                  placeholder="e.g. Bank Robbery — Koregaon Park"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                />
              </div>

              <div className="inputGroup">
                <label>Date of Crime *</label>
                <input
                  type="date"
                  value={crimeDate}
                  onChange={(e) => setCrimeDate(e.target.value)}
                  max={new Date().toISOString().split("T")[0]}
                />
              </div>

              <div className="inputGroup fullRow">
                <label>Case Description *</label>
                <textarea
                  rows="4"
                  placeholder="Describe the incident, location, and relevant details…"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                />
              </div>
            </div>
          </section>

          {/* ── Section 2: Team Assignment ──────────────────────── */}
          <section className="formSectionCard">
            <div className="sectionHeader flexSpaceBetween" style={{ padding: "1.25rem 1.5rem", borderBottom: "1px solid rgba(255,255,255,0.05)", marginBottom: 0 }}>
              <div style={{ display: "flex", alignItems: "center", gap: "0.6rem" }}>
                <div className="indicatorDot" style={{ background: "#8b5cf6" }} />
                <h2 style={{ margin: 0, fontSize: "0.75rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#94a3b8", fontWeight: 800 }}>
                  Team Assignment
                </h2>
              </div>
              <div className="headerToolbox">
                <div className="searchBox" ref={searchDropRef} style={{ position: "relative" }}>
                  <Search size={15} style={{ position: "absolute", left: "0.75rem", top: "50%", transform: "translateY(-50%)", color: "#475569" }} />
                  <input
                    type="text"
                    placeholder="Search team members…"
                    value={searchTerm}
                    onChange={handleSearch}
                  />
                  {searchResults.length > 0 && (
                    <div className="searchDropdown" style={{ width: "100%", top: "calc(100% + 4px)" }}>
                      {searchResults.map((member) => (
                        <div key={member._id} className="searchItem"
                          style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}
                          onClick={() => addMember(member)}>
                          <div>
                            <p style={{ margin: 0, fontWeight: 600, fontSize: "0.875rem" }}>{member.name}</p>
                            <p style={{ margin: 0, color: "#64748b", fontSize: "0.75rem" }}>
                              {member.role_id?.role_name?.replace(/_/g, " ")}
                            </p>
                          </div>
                          <Plus size={14} color="#818cf8" style={{ flexShrink: 0 }} />
                        </div>
                      ))}
                    </div>
                  )}
                  {searchTerm.length >= 1 && searchResults.length === 0 && (
                    <div className="searchDropdown" style={{ width: "100%", top: "calc(100% + 4px)", padding: "0.75rem 1rem" }}>
                      <p style={{ color: "#475569", fontSize: "0.8rem", margin: 0 }}>No members found for "{searchTerm}"</p>
                    </div>
                  )}
                </div>
                <FilterMember onFilterSelect={handleFilterSelection} />
              </div>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Lead Investigator *</label>
                <div className="selectWrapper">
                  <select value={leader} onChange={(e) => setLeader(e.target.value)}>
                    <option value="">— Select lead investigator —</option>
                    {leaders.map((l) => (
                      <option key={l._id} value={l._id}>{l.name}</option>
                    ))}
                  </select>
                  <ChevronDown className="dropdownIcon" size={16} />
                </div>
              </div>

              <div className="inputGroup">
                <label>
                  Team Members
                  {assignedMembers.length > 0 && (
                    <span style={{ marginLeft: "0.5rem", background: "rgba(99,102,241,0.15)", color: "#818cf8", fontSize: "0.7rem", padding: "1px 7px", borderRadius: 10, fontWeight: 700 }}>
                      {assignedMembers.length}
                    </span>
                  )}
                </label>
                <div className="tagDisplayArea">
                  {assignedMembers.length === 0 ? (
                    <span style={{ color: "#334155", fontSize: "0.8rem", alignSelf: "center" }}>Use the search above to add members…</span>
                  ) : (
                    assignedMembers.map((member) => (
                      <span key={member._id} className="memberTag">
                        {member.name}
                        <X size={13} className="tagRemove" onClick={() => removeMember(member._id)} />
                      </span>
                    ))
                  )}
                </div>
              </div>
            </div>
          </section>

          {/* ── Section 3: Case Settings ────────────────────────── */}
          <section className="formSectionCard">
            <div className="sectionHeader" style={{ padding: "1.25rem 1.5rem", borderBottom: "1px solid rgba(255,255,255,0.05)", marginBottom: 0 }}>
              <div className="indicatorDot" style={{ background: "#f59e0b" }} />
              <h2 style={{ margin: 0, fontSize: "0.75rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#94a3b8", fontWeight: 800 }}>
                Case Settings
              </h2>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Priority Level</label>
                <div className="selectWrapper">
                  <select value={priority} onChange={(e) => setPriority(e.target.value)}>
                    {priorities.map((p) => <option key={p}>{p}</option>)}
                  </select>
                  <ChevronDown className="dropdownIcon" size={16} />
                </div>
              </div>

              <div className="inputGroup">
                <label>Initial Status</label>
                <div className="selectWrapper">
                  <select value={status} onChange={(e) => setStatus(e.target.value)}>
                    {statuses.map((s) => <option key={s}>{s}</option>)}
                  </select>
                  <ChevronDown className="dropdownIcon" size={16} />
                </div>
              </div>
            </div>
          </section>

          {/* ── Footer buttons ─────────────────────────────────── */}
          <footer className="formFooter">
            <button className="btnCancel" onClick={() => navigate("/dashboard")} disabled={submitting}>
              Cancel
            </button>
            <button className="btnCreate" onClick={handleCreateCase} disabled={submitting}>
              {submitting
                ? <><div className="miniSpinner" style={{ width: 16, height: 16 }} /> Creating Case…</>
                : <><CheckCircle size={16} /> Create Case</>}
            </button>
          </footer>
        </div>
      </div>
    </div>
  );
}

export default CreatePage;
